pragma solidity ^0.8.20;

contract SafeMath {
    error Overflow();

    function safeAdd(uint256 a, uint256 b) external pure returns (uint256 c) {
        assembly {
            [[SLOT yul_add]]
            if [[SLOT overflow_pred]] {
                [[SLOT store_selector]]
                [[SLOT revert_call]]
            }
        }
    }
}
